 797→                    });
 798→                  },
 799→                },
 800→                dismissAction: {
 801→                  label: 'Cancel',
 802→                  style: 'cancel',
 803→                  onAction: () => {},
 804→                },
 805→              });
 806→            },
 807→          },
 808→        ],
 809→      },
 810→    ],
 811→    [
 812→      selectedItem,
 813→      isCalculatorSelected,
 814→      calculatorResult,
 815→      showToast,
 816→      showHUD,
 817→      confirmAlert,
 818→      isFavorite,
 819→      handleToggleFavorite,
 820→    ],
 821→  );
 822→
 823→  const activeDescendantId =
 824→    allItems.length > 0 ? `list-item-${selectedIndex}` : undefined;
 825→
 826→  const contextLabel =
 827→    nav.breadcrumbs.length > 0
 828→      ? nav.breadcrumbs[nav.breadcrumbs.length - 1]!.label
 829→      : 'Raycast';
 830→
 831→  const isCompact = !query.trim();
 832→
 833→  useEffect(() => {
 834→    onCompactChange?.(isCompact);
 835→  }, [
 836→    isCompact,
 837→    onCompactChange,
 838→  ]);
 839→
 840→  return (
 841→    <>
 842→      <SearchBar
 843→        value={query}
 844→        onChange={handleQueryChange}
 845→        activeDescendantId={activeDescendantId}
 846→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
 847→        cyclingPlaceholders={CYCLING_PLACEHOLDERS}
 848→        dropdown={
 849→          <SearchDropdown
 850→            sections={searchFilterSections}
 851→            value={filterValue}
 852→            onChange={handleFilterChange}
 853→          />
 854→        }
 855→      />
 856→      <div
 857→        className="command-palette__collapsible"
 858→        aria-hidden={isCompact}
 859→        inert={isCompact ? true : undefined}
 860→      >
 861→        <div className="command-palette__collapsible-inner">
 862→          <div className="command-palette__body">
 863→            <div className="command-palette__list-container">
 864→              {allItems.length === 0 ? (
 865→                <EmptyState
 866→                  icon={<MagnifyingGlassIcon size={48} />}
 867→                  title="No Results"
 868→                  description="Try a different search term"
 869→                />
 870→              ) : (
 871→                <List
 872→                  itemCount={allItems.length}
 873→                  onActiveIndexChange={handleActiveIndexChange}
 874→                  onAction={handleDrillIn}
 875→                  detail={
 876→                    detail ? (
 877→                      <Detail
 878→                        markdown={detail.markdown}
 879→                        metadata={
 880→                          detail.metadata ? (
 881→                            <DetailMetadata>
 882→                              {detail.metadata.map(renderMetadataEntry)}
 883→                            </DetailMetadata>
 884→                          ) : undefined
 885→                        }
 886→                      />
 887→                    ) : undefined
 888→                  }
 889→                >
 890→                  {(() => {
 891→                    let globalIndex = 0;
 892→                    return (
 893→                      <>
 894→                        {calculatorResult && (
 895→                          <ListSection title="Result">
 896→                            <ListItem
 897→                              index={globalIndex++}
 898→                              title={`= ${calculatorResult}`}
 899→                              subtitle={query.trim()}
 900→                              icon={<CalculatorIcon />}
 901→                              accessories={[{ text: 'Copy' }]}
 902→                            />
 903→                          </ListSection>
 904→                        )}
 905→                        {filtered.map(section => (
 906→                          <ListSection
 907→                            key={section.title}
 908→                            title={section.title}
 909→                          >
 910→                            {section.items.map(item => {
 911→                              const idx = globalIndex++;
 912→                              const showStar =
 913→                                isFavorite(item.id) &&
 914→                                section.title !== 'Favorites';
 915→                              const itemAccessories = showStar
 916→                                ? [
 917→                                    {
 918→                                      icon: <StarFilledIcon size={12} />,
 919→                                      tooltip: 'Favorite',
 920→                                    },
 921→                                    ...(item.accessories ?? []),
 922→                                  ]
 923→                                : item.accessories;
 924→                              return (
 925→                                <ListItem
 926→                                  key={item.id}
 927→                                  index={idx}
 928→                                  title={item.title}
 929→                                  subtitle={item.subtitle}
 930→                                  icon={item.icon}
 931→                                  accessories={itemAccessories}
 932→                                  query={query || undefined}
 933→                                />
 934→                              );
 935→                            })}
 936→                          </ListSection>
 937→                        ))}
 938→                      </>
 939→                    );
 940→                  })()}
 941→                </List>
 942→              )}
 943→            </div>
 944→          </div>
 945→          <ActionPanel
 946→            contextLabel={contextLabel}
 947→            actions={[
 948→              {
 949→                label: isCalculatorSelected ? 'Copy Result' : 'Open',
 950→                shortcut: <Kbd keys={['↵']} />,
 951→              },
 952→              {
 953→                label: 'Actions',
 954→                shortcut: (
 955→                  <Kbd
 956→                    keys={[
 957→                      '⌘',
 958→                      'K',
 959→                    ]}
 960→                  />
 961→                ),
 962→                onClick: toggleActions,
 963→              },
 964→            ]}
 965→            dropdownOpen={actionsOpen}
 966→            dropdownSections={dropdownSections}
 967→            onDropdownClose={closeActions}
 968→          />
 969→        </div>
 970→      </div>
 971→      {quickLookOpen && selectedItem?.detail && (
 972→        <QuickLook title={selectedItem.title} onClose={closeQuickLook}>
 973→          <Detail
 974→            markdown={selectedItem.detail.markdown}
 975→            metadata={
 976→              selectedItem.detail.metadata ? (
 977→                <DetailMetadata>
 978→                  {selectedItem.detail.metadata.map(renderMetadataEntry)}
 979→                </DetailMetadata>
 980→              ) : undefined
 981→            }
 982→          />
 983→        </QuickLook>
 984→      )}
 985→      {alertState && (
 986→        <Alert
 987→          title={alertState.title}
 988→          message={alertState.message}
 989→          icon={alertState.icon}
 990→          primaryAction={alertState.primaryAction}
 991→          dismissAction={alertState.dismissAction}
 992→          onDismiss={dismissAlert}
 993→        />
 994→      )}
 995→      <ToastContainer toasts={toasts} onDismiss={hideToast} />
 996→      <HUDContainer items={hudItems} />
 997→    </>
 998→  );
 999→}
